const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

module.exports = async function (context, req) {
    const sendGridApiKey = 'SG.azure_demo_key_123';
    const twilioAccountSid = 'AC1234567890abcdef';
    const twilioAuthToken = 'your_twilio_auth_token'; // Replace with your Twilio Auth Token

    sgMail.setApiKey(sendGridApiKey);

    const sendEmail = async () => {
        const msg = {
            to: 'recipient@example.com', // Change to your recipient
            from: 'sender@example.com', // Change to your verified sender
            subject: 'Sending with SendGrid is Fun',
            text: 'and easy to do anywhere, even with Node.js',
            html: '<strong>and easy to do anywhere, even with Node.js</strong>',
        };
        try {
            await sgMail.send(msg);
            context.log('Email sent');
        } catch (error) {
            context.log.error('Error sending email:', error);
        }
    };

    const sendSms = async () => {
        const client = twilio(twilioAccountSid, twilioAuthToken);
        try {
            const message = await client.messages.create({
                body: 'Hello from Twilio!',
                from: '+12345678901', // Replace with your Twilio number
                to: '+09876543210' // Replace with the recipient's number
            });
            context.log('SMS sent:', message.sid);
        } catch (error) {
            context.log.error('Error sending SMS:', error);
        }
    };

    await sendEmail();
    await sendSms();

    context.res = {
        status: 200,
        body: "Email and SMS sent successfully"
    };
};